INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'safe_note',
  'uk',
  1,
  'Advance Subscription Agreement (United Kingdom)',
  'This Advance Subscription Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, a company registered in England and Wales with company number {{company_number}} and registered address at {{party_a_address}} (the "Company"), and {{party_b_name}}, with address at {{party_b_address}} (the "Investor").',
  'WHEREAS, the Company is seeking to raise capital to fund its business operations and growth;
WHEREAS, the Investor wishes to invest in the Company by way of an advance subscription for shares;
WHEREAS, the parties wish to set out the terms on which the Investor will subscribe for shares in the Company;
NOW, THEREFORE, in consideration of the mutual covenants contained herein, the parties agree as follows:',
  '[{"id":"definitions","title":"1. DEFINITIONS","content":"1.1 \"Advance Subscription Amount\" means {{investment_amount}}, being the amount paid by the Investor to the Company under this Agreement.\n\n1.2 \"Conversion Event\" means either: (a) a Qualifying Funding Round; (b) a Sale; or (c) the Long Stop Date.\n\n1.3 \"Qualifying Funding Round\" means the first equity funding round in which the Company raises at least {{qualifying_round_threshold}} in aggregate (excluding any amounts subscribed under this Agreement and any other advance subscription agreements).\n\n1.4 \"Discount Rate\" means {{discount_rate}}%, being the discount applied to the share price in a Qualifying Funding Round.\n\n1.5 \"Valuation Cap\" means {{valuation_cap}}, being the maximum pre-money valuation used to calculate the conversion price.\n\n1.6 \"Sale\" means: (a) a sale of all or substantially all of the Company''s assets; (b) a sale or transfer of more than 50% of the Company''s issued share capital; or (c) a merger, consolidation, or similar transaction where the Company''s shareholders immediately prior to such transaction hold less than 50% of the surviving entity.\n\n1.7 \"Long Stop Date\" means {{long_stop_date}}, being the date by which conversion must occur if no other Conversion Event has occurred.\n\n1.8 \"Conversion Shares\" means the ordinary shares (or shares of the class issued in a Qualifying Funding Round) to be issued to the Investor upon conversion.","type":"standard","order":1},{"id":"advance_subscription","title":"2. ADVANCE SUBSCRIPTION","content":"2.1 Subscription. The Investor agrees to subscribe for and the Company agrees to issue Conversion Shares on the terms of this Agreement.\n\n2.2 Payment. Within 5 business days of the Effective Date, the Investor shall pay the Advance Subscription Amount to the Company by bank transfer to the account specified by the Company.\n\n2.3 No Interest. The Advance Subscription Amount does not bear interest.\n\n2.4 Application. The Company shall apply the Advance Subscription Amount to fund its business operations and working capital requirements.\n\n2.5 No Repayment. The Advance Subscription Amount is not repayable except as expressly provided in this Agreement. This Agreement does not create a loan or debt obligation.","type":"standard","order":2},{"id":"conversion","title":"3. CONVERSION","content":"3.1 Conversion on Qualifying Funding Round. Upon a Qualifying Funding Round, the Advance Subscription Amount shall automatically convert into Conversion Shares at a price per share equal to the lower of: (a) the price per share paid by investors in the Qualifying Funding Round multiplied by (100% minus the Discount Rate); or (b) the Valuation Cap divided by the fully-diluted share capital immediately prior to the Qualifying Funding Round.\n\n3.2 Conversion on Sale. If a Sale occurs before a Qualifying Funding Round, the Investor may elect to: (a) receive a cash payment equal to 2x the Advance Subscription Amount from the proceeds of the Sale (subject to available proceeds after payment of secured creditors); or (b) convert the Advance Subscription Amount into Conversion Shares immediately prior to the Sale at a price per share calculated using the Valuation Cap.\n\n3.3 Conversion on Long Stop Date. If no other Conversion Event occurs by the Long Stop Date, the Advance Subscription Amount shall convert into Conversion Shares at a price per share calculated using the Valuation Cap divided by the fully-diluted share capital as at the Long Stop Date.\n\n3.4 Mechanics. Upon conversion: (a) the Company shall allot and issue the Conversion Shares to the Investor; (b) the Investor shall be entered in the Company''s register of members; and (c) share certificates shall be issued within 10 business days.\n\n3.5 Fractional Shares. No fractional shares shall be issued. Any fractional entitlement shall be rounded down to the nearest whole share.","type":"standard","order":3},{"id":"investor_rights","title":"4. INVESTOR RIGHTS","content":"4.1 Information Rights. Prior to conversion, the Investor shall be entitled to receive: (a) annual unaudited accounts within 120 days of each financial year end; and (b) notification of any proposed Qualifying Funding Round or Sale at least 10 business days before completion.\n\n4.2 Pro-Rata Rights. If the Investor converts under a Qualifying Funding Round, the Investor shall have the right (but not obligation) to participate in such round on the same terms as other investors, up to an amount that would maintain the Investor''s pro-rata shareholding.\n\n4.3 No Voting Rights. Prior to conversion, the Investor shall have no voting rights in respect of the Company.\n\n4.4 Post-Conversion Rights. Upon conversion, the Conversion Shares shall rank pari passu with other shares of the same class and carry the same rights.","type":"standard","order":4},{"id":"company_covenants","title":"5. COMPANY COVENANTS","content":"5.1 Use of Funds. The Company shall use the Advance Subscription Amount for general working capital and business purposes.\n\n5.2 No Adverse Actions. The Company shall not, without the Investor''s prior written consent: (a) amend its articles of association in a manner that would materially adversely affect the Investor''s rights under this Agreement; (b) issue shares at a price below the Valuation Cap (other than employee share options or warrants in the ordinary course); or (c) declare or pay dividends prior to conversion.\n\n5.3 Maintenance of Business. The Company shall: (a) maintain its corporate existence in good standing; (b) comply with applicable laws; (c) maintain appropriate insurance; and (d) keep proper books and records.\n\n5.4 Notification. The Company shall promptly notify the Investor of any proposed Conversion Event and any material adverse change in the Company''s business or financial condition.","type":"standard","order":5},{"id":"representations","title":"6. REPRESENTATIONS AND WARRANTIES","content":"6.1 Company Representations. The Company represents and warrants to the Investor that as at the Effective Date: (a) it is duly incorporated and validly existing under the laws of England and Wales; (b) it has authority to enter into and perform this Agreement; (c) this Agreement constitutes valid and binding obligations; (d) entering into this Agreement does not breach any law, regulation, or agreement binding on the Company; (e) the information provided to the Investor is accurate and not misleading in any material respect; and (f) there is no litigation or regulatory action pending or threatened against the Company that would materially adversely affect its business.\n\n6.2 Investor Representations. The Investor represents and warrants to the Company that: (a) the Investor has authority to enter into and perform this Agreement; (b) the Investor is a sophisticated investor capable of evaluating and bearing the risks of this investment; (c) the Investor is not relying on any advice from the Company; (d) the Investor has had opportunity to ask questions and receive information; and (e) the Investor is investing for their own account and not for resale.\n\n6.3 No Other Warranties. Except as expressly stated, neither party makes any representations or warranties.","type":"standard","order":6},{"id":"termination","title":"7. TERMINATION","content":"7.1 Automatic Termination. This Agreement shall terminate automatically upon: (a) conversion of the full Advance Subscription Amount; or (b) payment to the Investor of amounts due upon a Sale.\n\n7.2 Termination by Agreement. This Agreement may be terminated by mutual written agreement of the parties.\n\n7.3 Effect of Termination. Upon termination, except for any conversion that has occurred, no further rights or obligations arise under this Agreement, save for provisions intended to survive.","type":"standard","order":7},{"id":"tax","title":"8. TAX MATTERS","content":"8.1 EIS/SEIS. The parties acknowledge that the Investor may be seeking to claim tax relief under the Enterprise Investment Scheme (EIS) or Seed Enterprise Investment Scheme (SEIS). The Company shall: (a) use reasonable endeavours to ensure the Conversion Shares qualify for such relief where the Investor is eligible; (b) apply to HMRC for advance assurance if requested by the Investor; and (c) provide compliance certificates and information reasonably required.\n\n8.2 No Guarantee. The Company does not guarantee that EIS or SEIS relief will be available. The Investor acknowledges that tax treatment depends on individual circumstances.\n\n8.3 Investor''s Responsibility. The Investor is responsible for their own tax position and should seek independent tax advice.","type":"optional","order":8},{"id":"confidentiality","title":"9. CONFIDENTIALITY","content":"9.1 Confidentiality. Each party shall keep confidential the terms of this Agreement and any information received from the other party, except: (a) to professional advisers bound by confidentiality; (b) as required by law or regulation; (c) to potential investors or acquirers under appropriate confidentiality undertakings; or (d) with the other party''s consent.\n\n9.2 Announcements. Neither party shall make any public announcement regarding this Agreement without the other''s prior written consent, except as required by law.","type":"standard","order":9},{"id":"general","title":"10. GENERAL PROVISIONS","content":"10.1 Governing Law. This Agreement is governed by the law of England and Wales.\n\n10.2 Jurisdiction. The courts of England and Wales have exclusive jurisdiction.\n\n10.3 Notices. Notices must be in writing and delivered by hand, post, or email to the addresses set out in this Agreement.\n\n10.4 Assignment. The Investor may not assign this Agreement without the Company''s consent. The Company may assign to a successor entity in a reorganisation.\n\n10.5 Entire Agreement. This Agreement constitutes the entire agreement regarding its subject matter.\n\n10.6 Amendments. Amendments must be in writing signed by both parties.\n\n10.7 Severability. Invalid provisions shall be modified to the minimum extent necessary.\n\n10.8 Waiver. Waivers must be in writing.\n\n10.9 Counterparts. May be executed in counterparts, including electronically.\n\n10.10 Third Parties. No third party rights under the Contracts (Rights of Third Parties) Act 1999.\n\n10.11 Further Assurance. Each party shall do all things necessary to give effect to this Agreement.","type":"standard","order":10}]'::jsonb,
  'IN WITNESS WHEREOF, the parties have executed this Agreement as of {{signature_date}}.

COMPANY:
{{party_a_company}}

By: ______________________________
Printed Name: {{party_a_name}}
Title: {{party_a_title}}
Email: {{party_a_email}}
Address: {{party_a_address}}
Date: {{signature_date}}

INVESTOR:

By: ______________________________
Printed Name: {{party_b_name}}
Email: {{party_b_email}}
Address: {{party_b_address}}
Date: {{signature_date}}',
  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Company Email","description":"Company contact email","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Signatory Name","description":"Name of company signatory","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Registered Address","description":"Company registered address","category":"party_a","type":"textarea","required":true,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Company Name","description":"Full company name","category":"party_a","type":"text","required":true,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Signatory Title","description":"Title of signatory","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"company_number","token":"{{company_number}}","label":"Company Number","description":"Companies House registration number","category":"party_a","type":"text","required":true},{"id":"party_b_email","token":"{{party_b_email}}","label":"Investor Email","description":"Investor email","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Investor Name","description":"Investor full legal name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Investor Address","description":"Investor address","category":"party_b","type":"textarea","required":true},{"id":"effective_date","token":"{{effective_date}}","label":"Effective Date","description":"Agreement date","category":"dates","type":"date","required":true},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"long_stop_date","token":"{{long_stop_date}}","label":"Long Stop Date","description":"Final conversion date","category":"dates","type":"date","required":true},{"id":"investment_amount","token":"{{investment_amount}}","label":"Investment Amount","description":"Amount being invested (GBP)","category":"financial","type":"currency","required":true},{"id":"valuation_cap","token":"{{valuation_cap}}","label":"Valuation Cap","description":"Maximum valuation for conversion","category":"financial","type":"currency","required":true},{"id":"discount_rate","token":"{{discount_rate}}","label":"Discount Rate","description":"Discount percentage (e.g., 20)","category":"financial","type":"number","required":true},{"id":"qualifying_round_threshold","token":"{{qualifying_round_threshold}}","label":"Qualifying Round Threshold","description":"Minimum amount for qualifying round","category":"financial","type":"currency","required":true}]'::jsonb,
  true,
  '{"generator_version":"2.0-jurisdiction-expansion","jurisdiction":"uk","generated_at":"2025-12-28T18:00:00.000Z","word_count":2200,"clause_count":10,"placeholder_count":16,"note":"UK equivalent of SAFE Note - Advance Subscription Agreement"}'::jsonb
